    59→    fun init(context: Context, isNeedGetRegisterOptions: Boolean = true) {
    60→        this.context = context
    61→
    62→        isEnableGoogleOAuth.value = RegionUtil.getRegion(context, repo.getCurrentIpRegion(context).regionCode, null).isAllowGoogleOAuth
    63→                && RegionUtil.getRegion(context, repo.getUserRegion(context).regionCode, null).isAllowGoogleOAuth
    64→
    65→
    66→        if (RegionUtil.getRegion(context, repo.getCurrentIpRegion(context).regionCode, null).isAllowFacebookOAuth == null ||
    67→            RegionUtil.getRegion(context, repo.getUserRegion(context).regionCode, null).isAllowFacebookOAuth == null
    68→        ) {
    69→            isEnableFacebookOAuth.value = null
    70→        } else {
    71→            isEnableFacebookOAuth.value = RegionUtil.getRegion(context, repo.getCurrentIpRegion(context).regionCode, null).isAllowFacebookOAuth!!
    72→                    && RegionUtil.getRegion(context, repo.getUserRegion(context).regionCode, null).isAllowFacebookOAuth!!
    73→        }
    74→
    75→        if (isNeedGetRegisterOptions) {
    76→            performGetAllRegistrationOptionAndDefault()
    77→        }
    78→    }
