   149→    private fun performGetAllRegistrationOptionAndDefault() {
   150→        progressDialogObservable.value = true
   151→        return repo.getRegistrationOption(context, object : SpiResponse<SpiGetRegisterOptions.Response>() {
   152→            override fun onResponse(
   153→                resp: SpiGetRegisterOptions.Response?, status: Status, failCode: FailCode
   154→            ): Boolean {
   155→                progressDialogObservable.value = false
   156→                if (status === Status.SUCCESS) {
   157→                    return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
   158→                        ErrorCode.COMM0000 -> {
   159→                            repo.saveRegionList(context, resp.body.options!!.countries)
   160→                            repo.saveCurrencyList(context, resp.body.options!!.currencies)
   161→                            repo.setEnableReferAFriend(context, resp.body.enableReferAFriend)
   162→                            enableReferAFriend.value = resp.body.enableReferAFriend
   163→
   164→                            val isoCodeRegion = repo.getIsoRegion(context)
   165→                            val countryNameRegion = repo.getDefaultRegion(context, resp.body.preference!!.countryName)
   166→                            when {
   167→                                isoCodeRegion != null -> {
   168→                                    selectedRegion.value = isoCodeRegion!!
   169→                                    performGetAgeCurrencyListOfRegion()
   170→                                }
   171→
   172→                                countryNameRegion != null -> {
   173→                                    selectedRegion.value = countryNameRegion!!
   174→                                    selectedCurrency.value = repo.getDefaultCurrency(context, resp.body.preference!!.defcurrency)
   175→                                    currencyList = repo.getCurrencyListOfRegion(context, resp.body.preference!!.currencies)
   176→                                    legalAge.value = resp.body.preference!!.getLegalAge()
   177→                                    isEnableGoogleOAuth.value = RegionUtil.getRegion(context, resp.body.preference!!.region, null).isAllowGoogleOAuth
   178→                                    if (isEnableFacebookOAuth.value != null) isEnableFacebookOAuth.value = RegionUtil.getRegion(context, resp.body.preference!!.region, null).isAllowFacebookOAuth
   179→                                }
   180→
   181→                                else -> {
   182→                                    val regionList = repo.getRegionList(context)
   183→                                    if (regionList.isNotEmpty()) {
   184→                                        selectedRegion.value = regionList[0]
   185→                                        performGetAgeCurrencyListOfRegion()
   186→                                    }
   187→                                }
   188→                            }
   189→                            true
   190→                        }
   191→
   192→                        else -> false
   193→                    }
   194→                } else {
   195→                    return false
   196→                }
   197→            }
   198→        })
   199→    }
   200→
   201→    fun performGetAgeCurrencyListOfRegion() {
   202→        progressDialogObservable.value = true
   203→        return repo.getCurrencyCodeListOfRegion(context, selectedRegion.value!!.code, object : SpiResponse<SpiGetCountryPreference.Response>() {
   204→            override fun onResponse(
   205→                resp: SpiGetCountryPreference.Response?, status: Status, failCode: FailCode
   206→            ): Boolean {
   207→                progressDialogObservable.value = false
   208→                return if (status === Status.SUCCESS) {
   209→                    when (ErrorCode.valueOrGeneralError(resp!!.code)) {
   210→                        ErrorCode.COMM0000 -> {
   211→                            legalAge.value = resp.body.getLegalAge()
   212→
   213→                            selectedCurrency.value = repo.getDefaultCurrency(context, resp.body.defcurrency)
   214→                            currencyList = repo.getCurrencyListOfRegion(context, resp.body.currencies)
   215→                            isEnableGoogleOAuth.value = RegionUtil.getRegion(context, resp.body.region, null).isAllowGoogleOAuth
   216→                            if (isEnableFacebookOAuth.value != null) isEnableFacebookOAuth.value = RegionUtil.getRegion(context, resp.body.region, null).isAllowFacebookOAuth
   217→                            true
   218→                        }
   219→
   220→                        else -> false
   221→                    }
   222→                } else {
   223→                    false
   224→                }
   225→            }
   226→        })
   227→    }
