   229→    fun performOAuthRegister(
   230→        oAuthUserData: OAuthUserData,
   231→        email: String, userName: String, pwd: String, planData: EnterRegisterPlanData, isSendPromotionChecked: Boolean,
   232→    ) {
   233→        performRegister(
   234→            email = email,
   235→            userName = userName,
   236→            pwd = pwd,
   237→            planData = planData,
   238→            isSendPromotionChecked = isSendPromotionChecked,
   239→            oAuthUserData = oAuthUserData
   240→        )
   241→    }
