   243→    fun performRegister(
   244→        email: String, userName: String, pwd: String, planData: EnterRegisterPlanData, isSendPromotionChecked: Boolean,
   245→        oAuthUserData: OAuthUserData = OAuthUserData()
   246→    ) {
   247→        progressDialogObservable.value = true
   248→        var affiliateId: Int? = null
   249→        var referralCode: String? = null
   250→        when (planData.codeType) {
   251→            RegisterCodeType.AffiliateId -> affiliateId = planData.inputCode.toInt()
   252→            RegisterCodeType.ReferralCode -> referralCode = planData.inputCode
   253→            RegisterCodeType.None -> {}
   254→        }
   255→        return repo.submitRegistration(
   256→            context,
   257→            email = email,
   258→            userName = userName,
   259→            pwd = pwd,
   260→            region = selectedRegion.value!!,
   261→            currency = selectedCurrency.value!!,
   262→            affiliateId = affiliateId,
   263→            referralCode = referralCode,
   264→            isSendPromotionChecked = isSendPromotionChecked,
   265→            oAuthUserData = oAuthUserData,
   266→            callback = object : SpiResponse<SpiSubmitRegistration.Response>() {
   267→                override fun onResponse(
   268→                    resp: SpiSubmitRegistration.Response?, status: Status, failCode: FailCode
   269→                ): Boolean {
   270→                    progressDialogObservable.value = false
   271→                    return if (status === Status.SUCCESS) {
   272→                        when (valueOrGeneralError(resp!!.code)) {
   273→                            ErrorCode.COMM0000 -> {
   274→                                registerResponseStatus.value = RegisterRepository.Companion.RegisterReturnStatus.fromCode(resp!!.body.returnCode)
   275→                                if (registerResponseStatus.value == RegisterRepository.Companion.RegisterReturnStatus.SUBMIT_SUCCESS) {
   276→                                    if (oAuthUserData.oAuthType == Constants.OAuthType.Unknown) {
   277→                                        performLogin(userName, pwd)
   278→                                    } else {
   279→                                        performOAuthLoginAfterRegister(oAuthUserData)
   280→                                    }
   281→                                    true
   282→                                } else
   283→                                    false
   284→                            }
   285→
   286→                            else -> {
   287→                                false
   288→                            }
   289→                        }
   290→                    } else {
   291→                        false
   292→                    }
   293→                }
   294→            })
   295→    }
   296→
   297→    fun performLogin(userName: String, pwd: String) {
   298→        progressDialogObservable.value = true
   299→        return repo.login(context, userName, pwd, object : SpiResponse<SpiLogin.Response>() {
   300→            override fun onResponse(
   301→                resp: SpiLogin.Response?, status: Status, failCode: FailCode
   302→            ): Boolean {
   303→                progressDialogObservable.value = false
   304→                if (status === Status.SUCCESS) {
   305→                    return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
   306→                        ErrorCode.COMM0000 -> {
   307→                            repo.saveLoginSuccessInfo(context, resp.body)
   308→                            isRegisterLoginSuccess.value = true
   309→
   310→                            // Fetch the general setting by region
   311→                            repo.getGeneralSettings(context, Constants.UpdateDeviceInfoEntry.REGISTER)
   312→                            true
   313→                        }
   314→
   315→                        else -> {
   316→                            isRegisterLoginSuccess.value = false
   317→                            true
   318→                        }
   319→                    }
   320→                } else {
   321→                    return false
   322→                }
   323→            }
   324→        })
   325→    }
   326→
   327→    private fun performOAuthLoginAfterRegister(
   328→        oAuthUserData: OAuthUserData
   329→    ) {
   330→        progressDialogObservable.value = true
   331→        return repo.oAuthLogin(
   332→            context, oAuthUserData = oAuthUserData,
   333→            callback = object : SpiResponse<SpiLogin.Response>() {
   334→                override fun onResponse(
   335→                    resp: SpiLogin.Response?, status: Status, failCode: FailCode
   336→                ): Boolean {
   337→                    progressDialogObservable.value = false
   338→                    if (status === Status.SUCCESS) {
   339→                        return when (ErrorCode.valueOrGeneralError(resp!!.code)) {
   340→                            ErrorCode.COMM0000 -> {
   341→                                repo.saveLoginSuccessInfo(context, resp.body)
   342→                                isRegisterLoginSuccess.value = true
   343→
   344→                                // Fetch the general setting by region
   345→                                repo.getGeneralSettings(context, Constants.UpdateDeviceInfoEntry.REGISTER)
   346→                                true
   347→                            }
   348→
   349→                            else -> {
   350→                                isRegisterLoginSuccess.value = false
   351→                                true
   352→                            }
   353→                        }
   354→                    } else {
   355→                        return false
   356→                    }
   357→                }
   358→            })
   359→    }
   360→}

