    17→const val LOCK_PATTERN_FUNCTION_KEY: String = "LOCK_PATTERN_FUNCTION_KEY"
    18→const val LOCK_PATTERN_PASSWORD_KEY: String = "LOCK_PATTERN_PASSWORD_KEY"
    19→const val RESULT_DATA_SAVE_KEY: String = "RESULT_DATA_SAVE_KEY"
    20→
    21→@Parcelize
    22→enum class LockPatternFunction: Parcelable { SET_KEY, UNLOCK }
    23→enum class LockPatternState { KEY_SETTING, KEY_SETTING_DONE, KEY_SETTING_CONFIRM, KEY_SETTING_CONFIRM_DONE, UNLOCK }
    24→
    25→
    26→
    27→sealed interface LockPatternEffect {
    28→    data object ShowErrorPattern : LockPatternEffect
    29→    data object OpenBiometricPrompt : LockPatternEffect
    30→    data object AskEnableBioAuth : LockPatternEffect
    31→    data object Logout : LockPatternEffect
    32→    data class Finish(val ok: Boolean, val savedKey: String? = null) : LockPatternEffect
    33→
    34→}
    35→
    36→class LockPatternViewModel(private val savedState: SavedStateHandle): ViewModel() {
    37→
    38→    private val _state = MutableStateFlow(
    39→        LockPatternUiState(
    40→            function = savedState.get<LockPatternFunction>(LOCK_PATTERN_FUNCTION_KEY) ?: LockPatternFunction.SET_KEY,
    41→            lockKeyForUnlock = savedState.get<String>(LOCK_PATTERN_PASSWORD_KEY) ?: "1234",
    42→            state = if ((savedState.get<LockPatternFunction>(LOCK_PATTERN_FUNCTION_KEY)
    43→                    ?: LockPatternFunction.SET_KEY) == LockPatternFunction.UNLOCK
    44→            ) LockPatternState.UNLOCK else LockPatternState.KEY_SETTING
    45→        )
    46→    )
    47→    val state: StateFlow<LockPatternUiState> = _state.asStateFlow()
    48→
    49→    private val _effects = MutableSharedFlow<LockPatternEffect>()
    50→    val effects: SharedFlow<LockPatternEffect> = _effects.asSharedFlow()
    51→
    52→    private fun emitError() = viewModelScope.launch { _effects.emit(LockPatternEffect.ShowErrorPattern) }
    53→
    54→    private fun update(newState: LockPatternUiState) {
    55→        _state.value = newState
    56→    }
    57→
    58→    fun onBioContext(
    59→        biometricAvailable: Boolean,
    60→        lockPatternEnabled: Boolean,
    61→        enableBioAuth: Boolean,
    62→        setBioAuth: Boolean
    63→    ) {
    64→        if (!lockPatternEnabled) return
    65→        if (!biometricAvailable) return
    66→
    67→        viewModelScope.launch {
    68→            when {
    69→                enableBioAuth -> _effects.emit(LockPatternEffect.OpenBiometricPrompt)
    70→                !setBioAuth -> _effects.emit(LockPatternEffect.AskEnableBioAuth)
    71→            }
    72→        }
    73→    }
    74→
    75→
    76→    fun onPatternChanged(pass: String?) {
    77→        val s = _state.value
    78→        if (pass == null) {
    79→            when (s.state) {
    80→                LockPatternState.KEY_SETTING ->
    81→                    update(s.copy(state = LockPatternState.KEY_SETTING, canConfirm = false, showConfirm = false))
    82→                LockPatternState.KEY_SETTING_DONE ->
    83→                    update(s.copy(state = LockPatternState.KEY_SETTING, canConfirm = false, showConfirm = false))
    84→                LockPatternState.KEY_SETTING_CONFIRM, LockPatternState.KEY_SETTING_CONFIRM_DONE ->
    85→                    update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
    86→                LockPatternState.UNLOCK -> { /* no-op */ }
    87→            }
    88→            return
    89→        }
    90→
    91→        when (s.state) {
    92→            LockPatternState.KEY_SETTING -> {
    93→                update(
    94→                    s.copy(
    95→                        lockKeyForSave = pass,
    96→                        state = LockPatternState.KEY_SETTING_DONE,
    97→                        canConfirm = true,
    98→                        showConfirm = true
    99→                    )
   100→                )
   101→            }
   102→            LockPatternState.KEY_SETTING_CONFIRM -> {
   103→                if (s.lockKeyForSave == pass) {
   104→                    update(
   105→                        s.copy(
   106→                            state = LockPatternState.KEY_SETTING_CONFIRM_DONE,
   107→                            canConfirm = true, showConfirm = true
   108→                        )
   109→                    )
   110→                } else {
   111→                    emitError()
   112→                }
   113→            }
   114→            LockPatternState.KEY_SETTING_CONFIRM_DONE -> {
   115→                if (s.lockKeyForSave == pass) {
   116→                } else {
   117→                    emitError()
   118→                    update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
   119→                }
   120→            }
   121→            LockPatternState.UNLOCK -> {
   122→                if (s.lockKeyForUnlock == pass) {
   123→                    viewModelScope.launch { _effects.emit(LockPatternEffect.Finish(ok = true)) }
   124→                } else {
   125→                    val cnt = s.unlockErrorCount + 1
   126→                    emitError()
   127→                    if (cnt >= 5) {
   128→                        viewModelScope.launch { _effects.emit(LockPatternEffect.Logout) }
   129→                    }
   130→                    update(s.copy(unlockErrorCount = cnt))
   131→                }
   132→            }
   133→            else -> {}
   134→        }
   135→    }
   136→
   137→    fun onClickCancel() {
   138→        val s = _state.value
   139→        when (s.state) {
   140→            LockPatternState.KEY_SETTING -> {
   141→                viewModelScope.launch { _effects.emit(LockPatternEffect.Finish(ok = false)) }
   142→            }
   143→            LockPatternState.KEY_SETTING_DONE,
   144→            LockPatternState.KEY_SETTING_CONFIRM -> {
   145→                update(
   146→                    s.copy(
   147→                        state = LockPatternState.KEY_SETTING,
   148→                        canConfirm = false,
   149→                        showConfirm = false
   150→                    )
   151→                )
   152→            }
   153→            LockPatternState.KEY_SETTING_CONFIRM_DONE -> {
   154→                update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
   155→            }
   156→            LockPatternState.UNLOCK -> {
   157→            }
   158→        }
   159→    }
   160→
   161→    fun onClickConfirm() {
   162→        val s = _state.value
   163→        when (s.state) {
   164→            LockPatternState.KEY_SETTING_DONE -> {
   165→                update(s.copy(state = LockPatternState.KEY_SETTING_CONFIRM, canConfirm = false, showConfirm = false))
   166→            }
   167→            LockPatternState.KEY_SETTING_CONFIRM_DONE -> {
   168→                viewModelScope.launch { _effects.emit(LockPatternEffect.AskEnableBioAuth) }
   169→            }
   170→            else -> Unit
   171→        }
   172→    }
   173→
   174→    fun saveKey() {
   175→        viewModelScope.launch {
   176→            _effects.emit(LockPatternEffect.Finish(ok = true, savedKey = _state.value.lockKeyForSave))
   177→        }
   178→    }
   179→
   180→    fun onDecideEnableBioAuth() {
   181→        viewModelScope.launch {
   182→            _effects.emit(LockPatternEffect.Finish(ok = true, savedKey = _state.value.lockKeyForSave))
   183→        }
   184→    }
   185→
   186→    fun onBiometricSucceededFromDialog() {
   187→        viewModelScope.launch { _effects.emit(LockPatternEffect.Finish(ok = true)) }
   188→    }
   189→
   190→    fun goToKeySetting() {
   191→        update(_state.value.copy(state = LockPatternState.KEY_SETTING, canConfirm = false, showConfirm = false))
   192→    }
