   511→        if (result.resultCode == Activity.RESULT_OK) {
   512→            val dataIntent = result.data
   513→            val affData = if (dataIntent != null) Gson().fromJson(
   514→                dataIntent.getStringExtra(EnterAffiliateActivity.KEY_ENTER_AFFILIATE_DATA),
   515→                EnterRegisterPlanData::class.java
   516→            ) else EnterRegisterPlanData()
   517→
   518→            mViewModel.affiliateData = affData
   519→            val title = when (affData.codeType) {
   520→                RegisterCodeType.AffiliateId -> getString(
   521→                    R.string.str_colon_space_str,
   522→                    getString(UiStr.TITAFFILIATESID),
   523→                    affData.inputCode
   524→                )
   525→
   526→                RegisterCodeType.ReferralCode -> getString(
   527→                    R.string.str_colon_space_str,
   528→                    getString(UiStr.TITREFERRALCODE),
   529→                    affData.inputCode
   530→                )
   531→
   532→                RegisterCodeType.None -> ""
   533→            }
   534→            val spannableStr = SpannableStringBuilder(title)
   535→            if (!TextUtils.isEmpty(affData.inputCode)) {
   536→                spannableStr.setSpan(
   537→                    StyleSpan(Typeface.BOLD),
   538→                    title.indexOf(affData.inputCode, ignoreCase = true),
   539→                    title.indexOf(affData.inputCode, ignoreCase = true) + affData.inputCode.length,
